/**
 * Generate Parallel firewall config.
 *
 * Data source: https://docs.parallel.ai/api-reference/tasks/create-task-run
 *
 * Parallel API requests use the x-api-key header with PARALLEL_API_KEY.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.parallel.ai/api-reference/tasks/create-task-run";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffee00";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Parallel API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:parallel",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const parallelFirewall = {",
    '  name: "parallel",',
    '  description: "Parallel API",',
    "  placeholders: {",
    `    PARALLEL_API_KEY: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.parallel.ai",',
    "      auth: {",
    "        headers: {",
    '          "x-api-key": "${{ secrets.PARALLEL_API_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Parallel firewall config...");
  const ts = generateTypeScript();
  writeOutput("parallel", ts, import.meta.dirname);
}
